<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller;use App\Models\AccountingPeriod;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;
class AccountingPeriodController extends Controller{public function index():JsonResponse{return response()->json(AccountingPeriod::query()->orderByDesc('start_date')->get());}public function store(Request $request):JsonResponse{$d=$request->validate(['name'=>['required','string','max:160'],'start_date'=>['required','date'],'end_date'=>['required','date','after_or_equal:start_date']]);abort_if(AccountingPeriod::query()->whereDate('start_date','<=',$d['end_date'])->whereDate('end_date','>=',$d['start_date'])->exists(),422,'Accounting periods cannot overlap.');return response()->json(AccountingPeriod::query()->create([...$d,'status'=>'open']),201);}public function close(AccountingPeriod $period):JsonResponse{$period->update(['status'=>'closed','closed_by'=>Auth::id(),'closed_at'=>now()]);return response()->json($period->refresh());}public function reopen(AccountingPeriod $period):JsonResponse{$period->update(['status'=>'open','closed_by'=>null,'closed_at'=>null]);return response()->json($period->refresh());}}
